// Helper functions to get unique values for filters
export const getUniqueDepartments = (): string[] => {
  return [...new Set(employees.map(e => e.department))].sort()
}

export const getUniqueBusinessUnits = (): string[] => {
  return [...new Set(employees.map(e => e.businessUnit))].sort()
}

export const getUniqueLocations = (): string[] => {
  return [...new Set(employees.map(e => e.location))].sort()
}

export const getUniqueJobPositions = (): string[] => {
  return [...new Set(employees.map(e => e.jobPosition))].sort()
}

// Get employee stats
export const getEmployeeStats = () => {
  const total = employees.length
  const active = employees.filter(e => e.status === "Active").length
  const inactive = employees.filter(e => e.status === "Inactive").length
  const exEmployee = employees.filter(e => e.status === "Ex-Employee").length
  
  return { total, active, inactive, exEmployee }
}
